import { Component, computed, effect, inject, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';

import { ClientResponse, EntitiesService } from '../../../../../api';
import {
  isBoolean,
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { AdminStateService } from '../../../services/admin-state.service';
import { EntitySectionBaseComponent } from '../../base';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  APP_FEATURE_FLAGS,
  AppFeatureFlagDefaults,
  AppFeatureSection,
  AppListsTranslations,
} from '../../../../../core/models';
import {
  createDropdownField,
  createListboxField,
  createModalListField,
  createNumberField,
  createTextAreaField,
  createTextField,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { Validators } from '@angular/forms';
import { firstValueFrom } from 'rxjs';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';

interface ExternalTabData {
  title: string;
  url: string;
  icon: string;
  section: string;
  order: number;
}

@Component({
  selector: 'app-feature-section',
  imports: [CommonModule, ButtonModule, GridComponent, DynamicFormComponent],
  templateUrl: './feature-section.component.html',
  styleUrl: './feature-section.component.scss',
})
export class FeatureSectionComponent<
  T extends ClientResponse,
> extends EntitySectionBaseComponent<T> {
  feature = input<AppFeatureSection>();
  featureBucket = APP_FEATURE_FLAGS;
  private readonly entitiesService = inject(EntitiesService);
  private readonly adminStateService = inject(AdminStateService);

  private readonly allFields = computed(() => {
    const section = this.feature();
    if (!section) return [];
    return [...(section.fields ?? []), ...(section.subfields ?? [])];
  });

  readonly entityDetails = computed(() => {
    const entityDetails = this.entity();
    const fields = this.allFields();
    const flags = entityDetails?.flags?.[this.featureBucket] as
      | Record<string, unknown>
      | undefined;

    if (isNullOrUndefined(entityDetails) || !flags) return [];

    return fields.map((field) => {
      const value = flags[field.id];
      const defaultValue = AppFeatureFlagDefaults[field.id]; // Default value from the defaults map
      const defaultValueFormatted = !isEmpty(defaultValue)
        ? `${this.formatFeatureValue(defaultValue)} (Default)`
        : 'None';

      return {
        key: field.title,
        value: isDefined(value)
          ? this.formatFeatureValue(value)
          : defaultValueFormatted,
      };
    });
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '', transform: 'capitalize' },
    ];

    effect(() => {
      const section = this.feature();
      if (section) {
        const fields = section?.fields.concat(section?.subfields ?? []) ?? [];

        // Create an array of promises for fields that need lookup values
        const lookupPromises = fields
          .filter((field) => isDefined(field.valueLookup))
          .map((field) =>
            this.getLookupValues(field.valueLookup)
              .then((result) => {
                field.values = result;
                return field;
              })
              .catch(() => field),
          );

        // Wait for all lookups to complete, then update form
        if (lookupPromises.length > 0) {
          Promise.all(lookupPromises)
            .then(() => {
              this.updateFormFields();
            })
            .catch(() => {});
        } else {
          // No lookups needed, update form immediately
          this.updateFormFields();
        }
      }
    });
  }

  private formatFeatureValue(value: unknown): string {
    if (isBoolean(value)) {
      return value ? 'Enabled' : 'Disabled';
    }

    return value?.toString() ?? '';
  }

  protected override updateFormFields(): void {
    const entity = this.entity();
    const section = this.feature();
    const fields = section?.fields.concat(section?.subfields ?? []) ?? [];

    this.formFields = fields.map((field) => {
      const validations = [];
      if (field.required ?? false) {
        validations.push({
          name: 'required',
          validator: Validators.required,
          message: `${field.title} is required`,
        });
      }
      if (isDefined(field.min)) {
        validations.push({
          name: 'minLength',
          validator: Validators.min(field.min),
          message: `${field.title} must be at least ${field.min}`,
        });
      }
      if (isDefined(field.max)) {
        validations.push({
          name: 'maxLength',
          validator: Validators.max(field.max),
          message: `${field.title} must be at most ${field.max}`,
        });
      }
      switch (field.type) {
        case 'dropdown':
          return createDropdownField(
            field.id,
            field.title,
            (field.values ?? []).map((value) => ({
              label: value.value ?? '',
              value: value.key ?? '',
            })),
            entity?.flags?.[this.featureBucket]?.[
              field.id
            ] as unknown as string,
            {
              name: field.id,
              validations,
              props: {
                appendTo: 'body',
              },
              hint: field.hint,
            },
          );

        case 'number':
          return createNumberField(
            field.id,
            field.title,
            entity?.flags?.[this.featureBucket]?.[
              field.id
            ] as unknown as number,
            {
              name: field.id,
              validations,
              hint: field.hint,
            },
          );

        case 'checklist':
          return createListboxField(
            field.id,
            field.title,

            [],
            (field.values ?? []).map((value) => ({
              label: value.value,
              value: value.key?.toString() ?? '',
            })),
            {
              name: field.id,
              validations,
              hint: field.hint,
              props: {
                appendTo: 'body',
                multiple: true,
                optionLabel: 'label',
                optionValue: 'value',
                style: { height: '250px' },
              },
            },
          );

        case 'list':
          if (field.id === 'page-external-tabs') {
            const externalTabModalConfig: ListFieldModalConfig = {
              modalComponent: ModalListFormComponent,
              modalTitle: 'External Tab',
              defaultItemProvider: (): ExternalTabData => ({
                title: '',
                url: '',
                icon: 'browser',
                section: '',
                order: 0,
              }),
              listItemFormatter: (item: unknown) => {
                const tabItem = item as ExternalTabData;
                return {
                  id: tabItem.title,
                  display: `${tabItem.title} (${tabItem.url})`,
                  icon: tabItem.icon,
                };
              },

              modalFields: (item?: unknown): FormFieldConfig[] => {
                const tabItem = item as ExternalTabData | undefined;
                return [
                  createTextField('title', 'Title', tabItem?.title ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'Title is required',
                      },
                    ],
                  }),
                  createTextField('url', 'URL', tabItem?.url ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'URL is required',
                      },
                    ],
                  }),
                  createTextField(
                    'icon',
                    'Icon',
                    tabItem?.icon ?? 'browser',
                    {},
                  ),
                  createTextField(
                    'section',
                    'Section',
                    tabItem?.section ?? '',
                    {
                      hint: AppListsTranslations['FIELDS']['SECTION_DESC'],
                    },
                  ),
                  createNumberField('order', 'Order', tabItem?.order ?? 0, {
                    hint: AppListsTranslations['FIELDS']['ORDER_DESC'],
                  }),
                ];
              },
              subHeader:
                AppListsTranslations['MODALS']['EXTERNAL-TABS']['DESC'],
            };

            return createModalListField(
              field.id,
              field.title,
              (entity?.flags?.[this.featureBucket]?.[
                field.id
              ] as ExternalTabData[]) ?? [],
              {
                name: field.id,
                validations,
                hint: field.hint,
                props: { modalConfig: externalTabModalConfig },
              },
            );
          } else if (field.id === 'page-admin-customPanels') {
            const customPanelModalConfig: ListFieldModalConfig = {
              modalComponent: ModalListFormComponent,
              modalTitle: 'Custom Panel',
              defaultItemProvider: () => ({}),
              listItemFormatter: (item: unknown) => {
                const tabItem = item as ExternalTabData;
                return {
                  id: tabItem.title,
                  display: `${tabItem.title} (${tabItem.url})`,
                  icon: tabItem.icon,
                };
              },

              modalFields: (item?: unknown): FormFieldConfig[] => {
                const tabItem = item as ExternalTabData | undefined;
                return [
                  createTextField('title', 'Title', tabItem?.title ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'Title is required',
                      },
                    ],
                  }),
                  createTextField('url', 'URL', tabItem?.url ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'URL is required',
                      },
                    ],
                  }),
                ];
              },
              subHeader:
                AppListsTranslations['MODALS']['ADMIN-ENTITY-TABS']['DESC'],
            };

            return createModalListField(
              field.id,
              field.title,
              (entity?.flags?.[this.featureBucket]?.[
                field.id
              ] as ExternalTabData[]) ?? [],
              {
                name: field.id,
                validations,
                hint: field.hint,
                props: { modalConfig: customPanelModalConfig },
              },
            );
          } else if (field.id === 'page-overview-customPanels') {
            const customPanelModalConfig: ListFieldModalConfig = {
              modalComponent: ModalListFormComponent,
              modalTitle: 'Custom Panel',
              defaultItemProvider: () => ({}),
              listItemFormatter: (item: unknown) => {
                const tabItem = item as ExternalTabData;
                return {
                  id: tabItem.title,
                  display: `${tabItem.title} (${tabItem.url})`,
                  icon: tabItem.icon,
                };
              },

              modalFields: (item?: unknown): FormFieldConfig[] => {
                const tabItem = item as ExternalTabData | undefined;
                return [
                  createTextField('title', 'Title', tabItem?.title ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'Title is required',
                      },
                    ],
                  }),
                  createTextField('url', 'URL', tabItem?.url ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'URL is required',
                      },
                    ],
                  }),
                ];
              },
              subHeader:
                AppListsTranslations['MODALS']['OVERVIEW-TABS']['DESC'],
            };

            return createModalListField(
              field.id,
              field.title,
              (entity?.flags?.[this.featureBucket]?.[
                field.id
              ] as ExternalTabData[]) ?? [],
              {
                name: field.id,
                validations,
                hint: field.hint,
                props: { modalConfig: customPanelModalConfig },
              },
            );
          } else {
            return createTextField(
              field.id,
              field.title,
              entity?.flags?.[this.featureBucket]?.[
                field.id
              ] as unknown as string,
              {
                name: field.id,
                validations,
                hint: field.hint,
              },
            );
          }

        case 'memo':
          return createTextAreaField(
            field.id,
            field.title,
            entity?.flags?.[this.featureBucket]?.[
              field.id
            ] as unknown as string,
            {
              name: field.id,
              layout: 'horizontal',
              labelWidth: '1/3',
            },
          );

        case 'text':
        default:
          return createTextField(
            field.id,
            field.title,
            entity?.flags?.[this.featureBucket]?.[
              field.id
            ] as unknown as string,
            {
              name: field.id,
              validations,
              hint: field.hint,
            },
          );
      }
    });
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = { fields: formData };

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }

  getLookupValues(valueLookup: string | undefined) {
    const ownerId = this.entity()?.owner.id ?? '';
    switch (valueLookup) {
      case 'reports':
        return firstValueFrom(
          this.entitiesService.listReportDefinitions(ownerId),
        ).then((result) => {
          const reports = result.items.map((x) => {
            return {
              key: x.id,
              value: x.name,
            };
          });
          return reports.sort((a, b) => a.value.localeCompare(b.value));
        });

      case 'assetTypes':
        return firstValueFrom(
          this.entitiesService.listAssetTypes(ownerId),
        ).then((result) => {
          const assetTypes = result.items.map((x) => {
            return {
              key: x.id,
              value: x.name,
            };
          });
          return assetTypes.sort((a, b) => a.value.localeCompare(b.value));
        });

      case 'alert-actions': {
        const actions = [
          {
            key: 'request_video',
            value: 'Request Video',
          },
          {
            key: 'label_current_trip',
            value: 'Label Current Trip',
          },
        ];
        actions.sort((a, b) => a.value.localeCompare(b.value));
        return Promise.resolve(actions);
      }

      default:
        return Promise.resolve([]);
    }
  }
}
