// Angular imports
import {
  Component,
  computed,
  DestroyRef,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { ActivatedRoute, Data } from '@angular/router';
import {
  catchError,
  combineLatest,
  EMPTY,
  from,
  of,
  switchMap,
  tap,
  throwError,
} from 'rxjs';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

// Third-party imports
import { AccordionModule } from 'primeng/accordion';
import { DividerModule } from 'primeng/divider';
import { ProgressSpinner } from 'primeng/progressspinner';

// Application imports
import { ClientResponse } from '../../../../../../api';
import { ClientDataStrategy } from '../../../../strategies';
import { SectionConfigBuilder } from '../../../../factories';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../../shared/utils';
import { AdminDetailSection } from '../../../../models';
import { AppFeatures } from '../../../../../../core/models';
import { FeatureSectionComponent } from '../../../shared/feature-section/feature-section.component';
import { AuthDataService } from '../../../../../../core/services/auth-data.service';

interface ClientRouteData extends Data {
  client?: ClientResponse;
}

@Component({
  selector: 'app-client-details-container',
  imports: [AccordionModule, DividerModule, ProgressSpinner, CommonModule],
  templateUrl: './client-details-container.component.html',
  styleUrl: './client-details-container.component.scss',
})
export class ClientDetailsContainerComponent implements OnInit {
  protected informationSections = signal<AdminDetailSection[]>([]);
  protected settingsSections = signal<AdminDetailSection[]>([]);
  protected statisticsSections = signal<AdminDetailSection[]>([]);
  protected featuresSections = signal<AdminDetailSection[]>([]);
  protected changesSections = signal<AdminDetailSection[]>([]);
  protected loading = signal(true);
  protected entity = signal<ClientResponse | null>(null);
  protected error = signal<string | null>(null);
  protected defaultExpandedSections = 0;

  // Helper computed properties
  protected hasInformationSections = computed(
    () => this.informationSections().length > 0,
  );
  protected hasSettingsSections = computed(
    () => this.settingsSections().length > 0,
  );
  protected hasStatisticsSections = computed(
    () => this.statisticsSections().length > 0,
  );
  protected hasChangesSections = computed(
    () => this.changesSections().length > 0,
  );
  protected hasFeaturesSections = computed(
    () => this.featuresSections().length > 0,
  );

  // Services
  private readonly dataStrategy = inject(ClientDataStrategy);
  private readonly destroyRef = inject(DestroyRef);
  private readonly route = inject(ActivatedRoute);
  private readonly authDataService = inject(AuthDataService);

  ngOnInit(): void {
    this.initializeEntityData();
  }

  private initializeEntityData(): void {
    combineLatest([
      this.route.paramMap,
      this.route.parent?.parent?.data || of<ClientRouteData>({}),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        tap(() => {
          this.loading.set(true);
          this.setupSectionStructure();
        }),
        switchMap(([params, data]) => {
          const clientId = params.get('clientId');

          if (!isEmpty(data['client'])) {
            return of(data['client']);
          }

          if (isDefined(clientId)) {
            return from(this.dataStrategy.fetchById(clientId));
          }

          return throwError(() => new Error('Client ID not found'));
        }),
        catchError(() => {
          this.error.set('Failed to load client data');
          return EMPTY;
        }),
        tap((clientData) => {
          this.entity.set(clientData);
          this.loading.set(false);
          this.updateSectionsWithEntityData();
        }),
      )
      .subscribe();
  }

  private setupSectionStructure(): void {
    // Register information sections
    this.informationSections.set(
      SectionConfigBuilder.createClientInformationSections(null),
    );

    // Register settings sections
    this.settingsSections.set(
      SectionConfigBuilder.createClientSettingsSections(null),
    );

    // Register changes sections
    this.changesSections.set(
      SectionConfigBuilder.createClientChangesSections(null),
    );

    if (this.authDataService.getUserProfile()?.owner?.type !== 'client') {
      // Register features sections
      const appFeatures = Object.keys(AppFeatures);

      this.featuresSections.set(
        appFeatures
          .map((feature) =>
            SectionConfigBuilder.forClient(null)
              .addSection(feature, 'Features', FeatureSectionComponent)
              .build(),
          )
          .flat(),
      );
    }
  }

  private updateSectionsWithEntityData(): void {
    const entityData = this.entity();
    if (isNullOrUndefined(entityData)) return;

    // Update sections with entity data
    this.informationSections.set(
      SectionConfigBuilder.createClientInformationSections(entityData),
    );

    this.settingsSections.set(
      SectionConfigBuilder.createClientSettingsSections(entityData),
    );

    this.changesSections.set(
      SectionConfigBuilder.createClientChangesSections(entityData),
    );

    if (this.authDataService.getUserProfile()?.owner?.type !== 'client') {
      let appFeatures = Object.keys(AppFeatures);
      const useFlags = this.authDataService.flags;
      if (isNullOrUndefined(useFlags.assetPerformanceEnabled())) {
        // Asset performance is not available, hide the feature flag section.
        appFeatures = appFeatures.filter(
          (feature) => feature !== 'page-assetperformance',
        );
      }
      if (isNullOrUndefined(useFlags.deviceHealthEnabled())) {
        appFeatures = appFeatures.filter(
          (feature) => feature !== 'page-devicehealth',
        );
      }

      this.featuresSections.set(
        appFeatures
          .map((feature) =>
            SectionConfigBuilder.forClient(entityData)
              .addSection(
                feature,
                'Features',
                FeatureSectionComponent<ClientResponse>,
                undefined,
                {
                  feature: AppFeatures[feature],
                },
              )
              .build(),
          )
          .flat(),
      );
    }
  }

  // Method for child components to save data
  async updateEntity(updates: Partial<ClientResponse>): Promise<void> {
    const client = this.entity();
    if (isNullOrUndefined(client)) return;

    try {
      this.loading.set(true);
      const updatedEntity = await this.dataStrategy.update(client.id, updates);
      this.entity.set(updatedEntity);
    } catch (error) {
      this.error.set(
        `${error instanceof Error ? error.message : String(error)}`,
      );
    } finally {
      this.loading.set(false);
    }
  }

  // Helper method to combine inputs
  protected getSectionInputs(
    section: AdminDetailSection,
  ): Record<string, unknown> {
    return {
      ...section.componentInputs,
    };
  }
}
